+		baseURL := route.LongpollBridge.APIBase
+		if baseURL == "" {
+			baseURL = "https://ilinkai.weixin.qq.com"
+		}
+
+		state.mu.Lock()
+		state.botToken = token
+		state.baseURL = baseURL
+		state.status = "running"
+		state.mu.Unlock()
