+		}
+
+		status, lastErr, lastPoll := state.getStatus()
+		state.mu.RLock()
+		tokenCount := len(state.contextTokens)
+		state.mu.RUnlock()
+
+		writeJSON(w, http.StatusOK, map[string]any{
+			"ok":                  true,
+			"bridge_id":           route.ID,
+			"status":              status,
+			"last_error":          lastErr,
+			"last_poll_at":        lastPoll.Format(time.RFC3339),
+			"active_context_count": tokenCount,
+		})
+	}
+}
